FUNCTION CreateTranslationMatrix(tx, ty)
 RETURN [
 [1, 0, tx],
 [0, 1, ty],
 [0, 0, 1]
 ]
END FUNCTION

// Usage
M_translate = CreateTranslationMatrix(5, 10)
// Result: [[1,0,5],[0,1,10],[0,0,1]]

FUNCTION RotateAboutPoint(point, pivot, angle)
 // Step 1: Translate point so pivot is at origin
 T1 = CreateTranslationMatrix(-pivot.x, -pivot.y)

 // Step 2: Rotate about origin
 R = CreateRotationMatrix(angle)

 // Step 3: Translate back
 T2 = CreateTranslationMatrix(pivot.x, pivot.y)

 // Composite: T2 × R × T1
 M1 = MultiplyMatrices(T2, R)
 M_final = MultiplyMatrices(M1, T1)

 // Apply to point
 RETURN ApplyTransformation(M_final, point)
END FUNCTION

// Example: Rotate (3,3) about pivot (1,1) by 90°
result = RotateAboutPoint((3,3), (1,1), 90)
// Result: approximately (1, 3)
